def tooltip(row):
    return f"{row['region']}: {row['median']} PEN (n={row['n']})"
print(tooltip({"region": "Cusco", "median": 22.5, "n": 32}))

def pie(cap):
    return " | ".join(f"{k}: {v}" for k, v in cap.items())
print(pie({"unidad": "PEN", "n": 10}))
